VALUES
  ('elementary-8b44517b-moex-00857', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '勞動派遣是我國極為普遍的非典型勞動方式，不過直至2019年勞動基準法修正時才對之有所規範。請問 下列論述何者不符合我國勞動基準法之規定？', '["派遣事業單位得與派遣勞工訂定定期勞動契約", "要派單位不得於派遣事業單位與派遣勞工簽訂勞動契約前，有面試該派遣勞工或其他指定特定派遣勞 工之行為", "派遣事業單位積欠派遣勞工工資，經主管機關處罰時，派遣勞工得請求要派單位給付", "要派單位使用派遣勞工發生職業災害時，要派單位應與派遣事業單位連帶負勞動基準法所定雇主應負 職業災害補償之責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00858', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列敘述何者不符合勞動基準法及其施行細則對於離職後競業禁止約定之規定？', '["雇主有應受保護之正當營業利益時，始得與勞工為離職後競業禁止之約定", "縱使勞工擔任之職位或職務無法接觸或使用雇主之營業秘密，但為了企業之利益，仍得與勞工為有效 之離職後競業禁止約定", "離職後競業禁止之期間，最長不得逾二年", "雇主對勞工因不從事競業行為所受損失有合理補償，且每月補償金額不低於勞工離職時一個月平均工 資百分之五十"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
